package com.flowmind.user.controller;import com.flowmind.common.core.ApiResponse;import com.flowmind.user.service.UserService;import org.springframework.web.bind.annotation.*;@RestController @RequestMapping("/api/users") public class UserController{private final UserService service;public UserController(UserService service){this.service=service;}@GetMapping("/me") public ApiResponse<?> me(){return ApiResponse.success(service.me());}}
